const template = $.input.emailTemplate;
const sender = $.input.senderName || 'Sender';
const sheetUrl = $.input.spreadsheetUrl;

let prompt = 'You are an email marketing specialist. Generate personalized emails based on the template and recipient data.\n\n';
prompt += 'EMAIL TEMPLATE/PURPOSE: ' + template + '\n';
prompt += 'SENDER NAME: ' + sender + '\n';
prompt += 'SHEET URL: ' + sheetUrl + '\n\n';
prompt += 'Since I cannot access the Google Sheet directly, generate 3 sample personalized emails based on the template. Each should be unique and demonstrate the personalization approach.\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Create personalized HTML emails using <p> tags\n';
prompt += '- Keep each email 80-150 words\n';
prompt += '- Include the sender name in the signature\n';
prompt += '- Make subject lines compelling and personalized\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "emails": [\n';
prompt += '    {\n';
prompt += '      "to": "recipient@example.com",\n';
prompt += '      "name": "Recipient Name",\n';
prompt += '      "subject": "personalized subject",\n';
prompt += '      "body": "<p>HTML email body</p>"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalEmails": 3,\n';
prompt += '  "templateUsed": "description of approach"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { emails: [], totalEmails: 0, error: raw }; }

const ai = $.steps.parseAI.output;
const emails = ai.emails || [];
const iterations = $.steps.sendEmails.response.iterations || [];

let sentCount = 0;
let failedCount = 0;
iterations.forEach(iter => {
  if (iter.sendOne && !iter.sendOne.error) sentCount++;
  else failedCount++;
});

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Bulk Email Send Complete' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Emails:*\n' + emails.length },
  { type: 'mrkdwn', text: '*Successfully Sent:*\n' + sentCount }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Failed:*\n' + failedCount },
  { type: 'mrkdwn', text: '*Template:*\n' + (ai.templateUsed || 'custom').slice(0, 100) }
] });
blocks.push({ type: 'divider' });

let recipientList = '';
emails.slice(0, 10).forEach((e, i) => {
  const status = (iterations[i] && iterations[i].sendOne && !iterations[i].sendOne.error) ? ':white_check_mark:' : ':x:';
  recipientList += status + ' ' + (e.name || 'Unknown') + ' (' + e.to + ') - ' + (e.subject || '').slice(0, 50) + '\n';
});
if (emails.length > 10) recipientList += '... and ' + (emails.length - 10) + ' more';

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Recipients:*\n' + recipientList.slice(0, 1800) } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + Gmail + Google Sheets' }] });

const fallback = 'Bulk email: ' + sentCount + '/' + emails.length + ' sent successfully';
return { blocks, fallback };
